-  }
- if suricata.flow.has("state") {
-    ocsf.status_id = 99
-    ocsf.status = move suricata.flow.state
-  } else {
-    ocsf.status_id = 0
-    ocsf.status = "Unknown"
-  }
-} else {
-  ocsf.traffic = null
-  ocsf.status_id = 0
-  ocsf.status = "Unknown"
-}
